using namespace adsk::core;
using namespace adsk::fusion;

Ptr ui;

extern "C" XI_EXPORT bool run(const char* context)
{
    Ptr app = Application::get();
    if (!app)
        return false;

    ui = app->userInterface();
    if (!ui)
        return false;

    Ptr documents = app->documents();
    if (!documents)
        return false;

    Ptr doc = documents->add(DocumentTypes::FusionDesignDocumentType);
    if (!doc)
        return false;

    Ptr product = app->activeProduct();
    if (!product)
        return false;

    Ptr design = product;
    if (!design)
        return false;

    // Get the root component of the active design
    Ptr rootComp = design->rootComponent();
    if (!rootComp)
        return false;

    // Create sketch circle on the xz plane.
    Ptr sketches = rootComp->sketches();
    if (!sketches)
        return false;
    Ptr sketch = sketches->add(rootComp->xZConstructionPlane());
    if (!sketch)
        return false;
    Ptr sketchCurves = sketch->sketchCurves();
    if (!sketchCurves)
        return false;
    Ptr sketchCircles = sketchCurves->sketchCircles();
    if (!sketchCircles)
        return false;
    Ptr centerPoint = Point3D::create(0, 0, 0);
    if (!centerPoint)
        return false;
    Ptr sketchCircle = sketchCircles->addByCenterRadius(centerPoint, 10);
    if (!sketchCircle)
        return false;
    centerPoint = Point3D::create(15, 5, 0);
    if (!centerPoint)
        return false;
    sketchCircle = sketchCircles->addByCenterRadius(centerPoint, 4);
    if (!sketchCircle)
        return false;

    // Create a collection of entities for extrude
    Ptr profiles = ObjectCollection::create();
    if (!profiles)
        return false;
    Ptr sketchProfiles = sketch->profiles();
    if (!sketchProfiles)
        return false;
    Ptr sketchProfile = sketchProfiles->item(0);
    if (!sketchProfile)
        return false;
    profiles->add(sketchProfile);

    sketchProfile = sketchProfiles->item(1);
    if (!sketchProfile)
        return false;
    profiles->add(sketchProfile);

    // Create two cylinders with ExtrudeFeature using the profiles above.
    Ptr features = rootComp->features();
    if (!features)
        return false;
    Ptr extrudeFeats = features->extrudeFeatures();
    if (!extrudeFeats)
        return false;
    Ptr distance = adsk::core::ValueInput::createByReal(2.0);
    if (!distance)
        return false;
    Ptr extrudeFeature =
        extrudeFeats->addSimple(profiles, distance, adsk::fusion::FeatureOperations::NewBodyFeatureOperation);

    // Create a collection of entities for move
    Ptr brepBodies = extrudeFeature->bodies();
    if (!brepBodies)
        return false;
    Ptr brepBody = brepBodies->item(0);
    if (!brepBody)
        return false;
    Ptr entities1 = adsk::core::ObjectCollection::create();
    if (!entities1)
        return false;
    entities1->add(brepBody);

    // Create a transform to do move
    Ptr vector = adsk::core::Vector3D::create(0.0, 10.0, 0.0);
    if (!vector)
        return false;
    Ptr transform = adsk::core::Matrix3D::create();
    if (!transform)
        return false;
    transform->translation(vector);

    // Create a move feature
    Ptr moveFeats = features->moveFeatures();
    if (!moveFeats)
        return false;
    Ptr moveFeatureInput = moveFeats->createInput2(entities1);
    if (!moveFeatureInput)
        return false;
    moveFeatureInput->defineAsFreeMove(transform);
    Ptr moveFeature = moveFeats->add(moveFeatureInput);
    if (!moveFeature)
        return false;


    return true;
}
